import java.util.PriorityQueue;
import java.util.ArrayList;
import java.util.List;

public static long solve(long[][] grid, long k) {
    int m = grid.length;
    int n = grid[0].length;
    int maxK = (int) k;
    if (maxK == 0) {
        // No teleportation allowed, use only normal moves
        long[][] dist = new long[m][n];
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                dist[i][j] = Long.MAX_VALUE;
            }
        }
        dist[0][0] = 0;
        PriorityQueue<long[]> pq = new PriorityQueue<>((a, b) -> Long.compare(a[0], b[0]));
        pq.add(new long[]{0, 0, 0});
        while (!pq.isEmpty()) {
            long[] current = pq.poll();
            long cost = current[0];
            int i = current[1];
            int j = current[2];
            if (i == m - 1 && j == n - 1) return cost;
            if (cost > dist[i][j]) continue;
            int[] directions = {0, 1, 1, 0};
            for (int d = 0; d < 2; d++) {
                int ni = i + directions[d];
                int nj = j + directions[d];
                if (ni < m && nj < n) {
                    long newCost = cost + grid[ni][nj];
                    if (newCost < dist[ni][nj]) {
                        dist[ni][nj] = newCost;
                        pq.add(new long[]{newCost, ni, nj});
                    }
                }
            }
        }
        return -1;
    }

    // Precompute teleport lists
    List<List<int[]>> teleportList = new ArrayList<>();
    for (int i = 0; i < m; i++) {
        List<int[]> list = new ArrayList<>();
        for (int j = 0; j < n; j++) {
            List<int[]> temp = new ArrayList<>();
            for (int x = 0; x < m; x++) {
                for (int y = 0; y < n; y++) {
                    if (grid[x][y] <= grid[i][j]) {
                        temp.add(new int[]{x, y});
                    }
                }
            }
            list.add(temp);
        }
        teleportList.add(list);
    }

    // Initialize distance array
    long[][][] dist = new long[m][n][maxK + 1];
    for (int i = 0; i < m; i++) {
        for (int j = 0; j < n; j++) {
            for (int t = 0; t <= maxK; t++) {
                dist[i][j][t] = Long.MAX_VALUE;
            }
        }
    }
    dist[0][0][0] = 0;

    PriorityQueue<long[]> pq = new PriorityQueue<>((a, b) -> Long.compare(a[0], b[0]));
    pq.add(new long[]{0, 0, 0, 0});

    while (!pq.isEmpty()) {
        long[] current = pq.poll();
        long cost = current[0];
        int i = current[1];
        int j = current[2];
        int t = current[3];

        if (i == m - 1 && j == n - 1) {
            return cost;
        }

        if (cost > dist[i][j][t]) {
            continue;
        }

        // Process normal moves
        int[] directions = {0, 1, 1, 0};
        for (int d = 0; d < 2; d++) {
            int ni = i + directions[d];
            int nj = j + directions[d];
            if (ni < m && nj < n) {
                long newCost = cost + grid[ni][nj];
                if (newCost < dist[ni][nj][t]) {
                    dist[ni][nj][t] = newCost;
                    pq.add(new long[]{newCost, ni, nj, t});
                }
            }
        }

        // Process teleportation
        if (t < maxK) {
            for (int[] xy : teleportList.get(i).get(j)) {
                int x = xy[0];
                int y = xy[1];
                if (dist[x][y][t + 1] > cost) {
                    dist[x][y][t + 1] = cost;
                    pq.add(new long[]{cost, x, y, t + 1});
                }
            }
        }
    }

    return -1;
}
