import java.util.*;

public class Solution {
    public static long solve(long[][] grid, long k) {
        int m = grid.length;
        int n = grid[0].length;

        // Preprocess teleport lists
        List<int[]>[] teleportList = new List[m][n];
        for (int i = 0; i < m; i++) {
            teleportList[i] = new List[n];
            for (int j = 0; j < n; j++) {
                teleportList[i][j] = new ArrayList<>();
                for (int x = 0; x < m; x++) {
                    for (int y = 0; y < n; y++) {
                        if (grid[x][y] <= grid[i][j]) {
                            teleportList[i][j].add(new int[]{x, y});
                        }
                    }
                }
            }
        }

        // Dijkstra's algorithm
        long[][][] dist = new long[m][n][k+1];
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                for (int t = 0; t <= k; t++) {
                    dist[i][j][t] = Long.MAX_VALUE;
                }
            }
        }
        dist[0][0][0] = 0;

        PriorityQueue<long[]> pq = new PriorityQueue<>(Comparator.comparingLong(a -> a[0]));
        pq.offer(new long[]{0, 0, 0, 0});

        while (!pq.isEmpty()) {
            long[] current = pq.poll();
            long cost = current[0];
            int i = current[1];
            int j = current[2];
            int t = current[3];

            // Check if we reached the destination
            if (i == m-1 && j == n-1) {
                return cost;
            }

            // Regular moves: right and down
            int[] directions = {0, 1, 1, 0}; // right, down
            for (int d = 0; d < 2; d++) {
                int ni = i + directions[d];
                int nj = j + directions[d];
                if (ni < m && nj < n) {
                    long newCost = cost + grid[ni][nj];
                    if (newCost < dist[ni][nj][t]) {
                        dist[ni][nj][t] = newCost;
                        pq.offer(new long[]{newCost, ni, nj, t});
                    }
                }
            }

            // Teleport moves
            for (int[] xy : teleportList[i][j]) {
                int x = xy[0];
                int y = xy[1];
                if (t + 1 <= k) {
                    long newCost = cost;
                    if (newCost < dist[x][y][t+1]) {
                        dist[x][y][t+1] = newCost;
                        pq.offer(new long[]{newCost, x, y, t+1});
                    }
                }
            }
        }

        // If not found (should not happen)
        return -1;
    }
}

